    addressTh: "โชว์รูมกรุงเทพฯ, ประเทศไทย",
    addressEn: "Bangkok Showroom, Thailand",
    email: "contact@thumbtoe.shop",
    phone: "+66 (0) 2-123-4567",
    lineId: "@thumbtoe_th",
    lineUrl: "https://line.me/R/ti/p/@thumbtoe_th",
